BD-PB-BADSHIFT.example_violation:
Here is an example that triggers a violation:

#include <stdlib.h>

long long* getRandomNumbersBad()
{
    long long* res = new long long[8];
    for (int i = 7; i >= 0; i--) {
        int nextRand = rand() % (1 << 8);
        res[i] = nextRand << (8 * i); // VIOLATION
    }
    return res;
}

In the example above in the first four iterations we will get overflow because of shifting too many bits.

BD-PB-BADSHIFT.example_repair:
#include <stdlib.h>

long long* getRandomNumbersOK()
{
    long long* res = new long long[8];
    for (int i = 7; i >= 0; i--) {
        int nextRand = rand() % (1 << 8);
        res[i] = (long long)nextRand << (8 * i); // OK
    }
    return res;
}

BD-PB-INFREC.example_violation:
Here is an example that triggers a violation:

int binarySearch(int* tab, int a, int b, int val)
{
    int index = (a + b) / 2;
    if (tab[index] > val) {
        return binarySearch(tab, a, index - 1, val); // VIOLATION
    }
    return binarySearch(tab, index + 1, b, val); // VIOLATION
}

BD-PB-INFREC.example_repair:
int binarySearch(int* tab, int a, int b, int val)
{
    int index = (a + b) / 2;
    if (tab[index] > val) {
        return binarySearch(tab, a, index - 1, val);
    } else if (tab[index] < val) {
        return binarySearch(tab, index + 1, b, val);
    } else {
        return index;
    }
} // NO VIOLATION

CDD-DUPC.description:
This rule identifies duplicated code. The rule finds duplicated fragments across 
all tested code, whether or not the duplicated code appears in the same file.

Code duplication detection is focused on giving most useful results 
so the performed analysis is not just simple text tokens compare. 
Additional parameters which can be set for this rule can override compare result 
for different node types.   
Start and end position of code duplication block is calculated using several
internal rules, like:  
- start point can be placed only on statement beginning
- end point can be placed only on statement end
- end point can't leave start point scope (duplicated code block for example, can't start 
  in the middle of one function body and ends in different one)

For example:

@int foo(int a, int b)
{
    @int r;%
    @if (a < b) { 
        @r = b - a;%
    } else {       
        @r = a - b;%
    }         
    @return r;%
}

@ - marks possible start points for duplicated code part 
% - marks possible end points for duplicated code part

A violation is reported for each occurrence.
See also: CDD-DUPM

CDD-DUPC.example_violation:
Parameters: Ignore identifiers turned on, minimum duplicated tokens size set to 20.

int foo(int a, int b)
{
    int r;
    if (a < b) {      // duplicated code
        r = b - a;    // duplicated code
    } else {          // duplicated code
        r = a - b;    // duplicated code
    }                 // duplicated code
    return r;
}

int bar(int p, int q, bool v)
{
    int result;
    if (v) {
        if (p < q) {           // duplicated code
            result = q - p;    // duplicated code
        } else {               // duplicated code
            result = p - q;    // duplicated code
        }                      // duplicated code
    } else {
        return p + q;
    }
    return result;
}

CDD-DUPC.example_repair:
int foo(int a, int b)
{
    int r;
    if (a < b) {      
        r = b - a;  
    } else {          
        r = a - b;    
    }                 
    return r;
}

int bar(int p, int q, bool v)
{
    int result;
    if (v) {
        result = foo(p, q);   // use foo function here
    } else {
        result =  p + q;
    }
    return result;
}

