This rule cases when the value that is passed to a standard library function
as a parameter may be different than the value that the function expects.

This rule checks values that are passed to the following functions:

<ctype.h>
    Condition: c>=-1 && c<=255
        isalnum ( c );
        isalpha ( c );
        isblank ( c ); 
        iscntrl ( c );
        isdigit ( c );
        isgraph ( c );
        islower ( c );
        isprint ( c );
        ispunct ( c );
        isspace ( c );
        isupper ( c );
        isxdigit ( c );
        tolower ( c );
        toupper ( c );

<math.h>
    Condition: x>=-1 && x<=1
        acos[fl]  ( x );
        asin[fl]  ( x );    

    Condition: x>-1 && x<1
        atanh[fl]  ( x );    

    Condition: x>=0
        sqrt[fl]  ( x );
        log[fl]  ( x );
        log10[fl]  ( x );
        log2[fl]  ( x );

    Condition: x>=1
        acosh[fl]  ( x );

    Condition: x>=-1
        log1p[fl]  ( x );    

    Condition:  x != 0
        remainder[fl]  ( numer, x );
        remquo[fl]  ( numer, x, quot );
        fmod[fl]  ( numer, x );
        logb[fl]  ( x );
        ilogb[fl]  ( x );

    Condition: x > 0 || x is not an integer:
        lgamma[fl]  ( x );
        tgamma[fl]  ( x );

<stdio.h>

    Condition: character>=-128 && character<=255
        fputc ( character, stream );
        putc ( character, stream );
        ungetc ( character, stream );
        putchar ( character );

    Condition: non_neg>=0
        fgets ( str, non_neg, stream );
        fseek ( stream, non_neg, origin ); (when the origin parameter is set to SEEK_SET(0 assumed))

<string.h>

    Condition: value>=-128 && value<=255
        memchr ( ptr, value, size_t num );
        memset ( ptr, value, size_t num );
        strchr ( str, value );
        strrchr ( str, value );

<wchar.h>
    Condition: c>=0 && c<=255
        btowc ( c );

<stdlib.h>
    Condition: denom != 0
        div ( numer, denom );
        ldiv ( numer, denom );
        lldiv ( numer, denom );

    Condition: n != INT_MIN
        abs ( int n );

See also BD-API-BADPARAM, BD-API-CTYPE, BD-API-NEGPARAM

