#include <stdio.h>

void printStory(FILE* f)
{
	char storyName[50];
	fread(storyName, sizeof(char), 50, f); /* Reading story from a file */
	printf("%s", storyName);
}

MISRAC2012-DIR_4_14-k.example_repair:
Validate data prior to its usage:

