void foo ( int i )
{
  switch ( i )
  {
    case 0:
    default:              /* Violation: 'default' not first nor last  */
      i = 8;
      break;
    case 1:
      i = 7;
      break;
  }
  switch ( i )
  {
    case 0:
      i = 8;
      break;
    default:              /* Violation: 'default' not first nor last  */
      i = 10;
      break;
    case 1:
      i = 7;
      break;
  }
  switch ( i )
  {
    case 0:
      i = 8;
      break;
    default:              /* Violation: 'default' not first nor last  */
    case 1:
      i = 7;
      break;
  }
}

MISRAC2012-RULE_16_5-a.example_repair:
/* Examples of correct 'default' placements: */
void foo ( int i )
{
  switch ( i )
  {
    default:              /* OK: 'default' is first */
    case 0:
      i = 8;
      break;
    case 1:
      i = 7;
      break;
  }
  switch ( i )
  {
    default:              /* OK: 'default' is first */
      i = 10;
      break;
    case 0:
      i = 8;
      break;
    case 1:
      i = 7;
      break;
  }
  switch ( i )
  {
    case 0:
      i = 8;
      break;
    case 1:
    default:              /* OK: 'default' is last */
      i = 7;
      break;
  }
  switch ( i )
  {
    case 0:
      i = 8;
      break;
    case 1:
      i = 7;
      break;
    default:              /* OK: 'default' is last */
      i = 10;
      break;
  }
}

/* Lack of 'default' is not a violation of this rule: */
void bar ( int i )
{
  switch ( i )
  {
    case 0:
      i = 8;
      break;
    case 1:
      i = 7;
      break;
  }
}

MISRAC2012-RULE_16_6-a.example_violation:
void example ( int i )
{
  switch ( i )                        /* Violation */
  {
    case 0:
    case 1:
      /* A switch-clause */
      i = i + 1;
      break;
    default:
      /* There are no statements here so this is not counted
       * as a switch-clause */
  }

  switch ( i )                        /* Violation */
  {
    case 1:
    default:
      /* A switch-clause */
      i = i + 1;
      break;
  }
}

MISRAC2012-RULE_16_6-a.example_repair:
void repair ( int i )
{
  /* The first switch was rewritten into an 'if' */
  if ( ( i == 0 ) || ( i == 1 ) )
  {
    i = i + 1;
  }

  /* The second switch has been modified to contain two switch-clauses */
  switch ( i )                        /* Compliant */
  {
    case 1:
      /* A switch-clause */
      break;
    default:
      /* A switch-clause */
      i = i + 1;
      break;
  }
}

