MISRAC2012-RULE_1_3-f.example_violation:
int f1(int i) {
    int b[10];
    return b[i] + i++; // Violation
}

int f2(int i) {
    int b[10];
    i++;          // OK - The problem could be avoided by placing
    return b[i];  // the increment operation in a separate statement.
}

int fi(int);
void f3(int x, int y, int *p) {
    y = ++x + x;       // Violation
    y = x + fi(x++);   // Violation
    y = x + (x = 1);   // Violation
    *p = *p++;         // Violation

    y = ++x && x;  // OK - the order of evaluation is defined
    y = x++, x;    // OK - the order of evaluation is defined
    y = y++;       // OK - Variable 'y' is used to determine its stored value.
}

MISRAC2012-RULE_1_3-g.example_violation:
void f(int, int);

int f1(int& x) { return ++x; }
int f2(int* p);
int f3(const int* p);

int glob_var;

int g(int p) {
    glob_var = p;
    return glob_var;
}

void func1(int var, volatile int v1)
{
    f(f1(var), var);     // Violation
    f(var++, var);       // Violation
    f(f2(&var), var);    // Violation
    f(g(var), glob_var); // Violation
    f(v1, v1);           // Violation
}

void func2(int var)
{
    int temp = f1(var);
    f(temp, var);        // OK
    f(f3(&var), var);    // OK
}

