class SimpleCalculatorFixed {
private:
    int add(int a, int b) {
        return a + b;
    }

    int substract(int a, int b) {
        return a - b;
    }

    int multiply(int a, int b) {
        return a * b;
    }

    int divide(int a, int b) { // NO VIOLATION
        return a / b;
    }

public:
    void runCalculation() {
        int a, b, result;
        char operation;

        cin >> a >> operation >> b;

        switch (operation) {
        case '+':
            result = add(a, b);
            break;
        case '-':
            result = substract(a, b);
            break;

        case '*':
            result = multiply(a, b);
            break;

        case '/':
            result = divide(a, b); // FIXED
            break;
        }

        cout << result << endl;
    }
};

int main() {
    SimpleCalculatorFixed * calculator = new SimpleCalculatorFixed();
    calculator->runCalculation();
    delete calculator;
    return 0;
}

